import "./card.css";

import { cn } from "tailwind-variants";

import { CardContext } from "./card.context";
import { cardVariants, type CardVariants } from "./card.variants";

export type CardProps = CardVariants & React.ComponentProps<"div">;

export const CardRoot = ({ children, className, variant, ...props }: CardProps) => {
  const slots = cardVariants({ variant });

  return (
    <CardContext value={{ slots }}>
      <div className={cn(slots.root(), className)} {...props}>
        {children}
      </div>
    </CardContext>
  );
};

import { cn } from "tailwind-variants";

import { useCardContext } from "./card.context";

export type CardHeaderProps = React.ComponentProps<"div">;

export const CardHeader = ({ children, className, ...props }: CardHeaderProps) => {
  const { slots } = useCardContext();
  return (
    <div className={cn(slots.header(), className)} {...props}>
      {children}
    </div>
  );
};

import { cn } from "tailwind-variants";

import { useCardContext } from "./card.context";

export type CardTitleProps = React.ComponentProps<"h2">;

export const CardTitle = ({ children, className, ...props }: CardTitleProps) => {
  const { slots } = useCardContext();
  return (
    <h2 className={cn(slots.title(), className)} {...props}>
      {children}
    </h2>
  );
};

import { cn } from "tailwind-variants";

import { useCardContext } from "./card.context";

export type CardDescriptionProps = React.ComponentProps<"p">;

export const CardDescription = ({ children, className, ...props }: CardDescriptionProps) => {
  const { slots } = useCardContext();
  return (
    <p className={cn(slots.description(), className)} {...props}>
      {children}
    </p>
  );
};

import { cn } from "tailwind-variants";

import { useCardContext } from "./card.context";

export type CardContentProps = React.ComponentProps<"div">;

export const CardContent = ({ children, className, ...props }: CardContentProps) => {
  const { slots } = useCardContext();
  return (
    <div className={cn(slots.content(), className)} {...props}>
      {children}
    </div>
  );
};

import { createContext, useContext } from "react";

import { cardVariants } from "./card.variants";

export type CardContext = {
  slots: ReturnType<typeof cardVariants>;
};

export const CardContext = createContext<CardContext | null>(null);

export const useCardContext = () => {
  const context = useContext(CardContext);
  if (!context) {
    throw new Error("useCardContext must be used within a CardProvider");
  }
  return context;
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const cardVariants = tv({
  slots: {
    root: "card",
    header: "card__header",
    title: "card__title",
    description: "card__description",
    content: "card__content",
  },
  variants: {
    variant: {
      default: { root: "card--default" },
      outline: { root: "card--outline" },
    },
  },
  defaultVariants: {
    variant: "default",
  },
});

export type CardVariants = VariantProps<typeof cardVariants>;

.card {
  @apply bg-card text-card-foreground rounded-xl border;
}

.card--default {
  @apply shadow-sm;
}

.card--outline {
  @apply shadow-none;
}

.card__header {
  @apply flex flex-col gap-1.5 p-6;
}

.card__title {
  @apply text-lg leading-none font-semibold tracking-tight;
}

.card__description {
  @apply text-muted-foreground text-sm;
}

.card__content {
  @apply p-6 pt-0;
}

import { CardContent } from "./card-content";
import { CardDescription } from "./card-description";
import { CardHeader } from "./card-header";
import { CardRoot } from "./card-root";
import { CardTitle } from "./card-title";

export const Card = {
  Content: CardContent,
  Description: CardDescription,
  Header: CardHeader,
  Root: CardRoot,
  Title: CardTitle,
};

export { CardContent, CardDescription, CardHeader, CardRoot, CardTitle };

export { CardContext, useCardContext } from "./card.context";

export { type CardVariants, cardVariants } from "./card.variants";
